// ================================================================
// Discord bridge
// ================================================================
// This bridge uses the Discord Gateway and REST API only for message transport.
// The model response is generated by the same local CLI-backed AssistantRuntime.
import { chunkText } from "../utils/text.js";
import { DEFAULT_FETCH_TIMEOUT_MS, fetchWithTimeout } from "../utils/fetch.js";
import { pairedMessage, pairingRequiredMessage } from "./telegram.js";
import { connectorInputLimitMessage, connectorInputTooLong } from "./input-policy.js";
import { ConnectorRateLimiter, connectorRateLimitMessage } from "./rate-limit.js";
const DISCORD_GATEWAY_URL = "wss://gateway.discord.gg/?v=10&encoding=json";
const DISCORD_API_BASE = "https://discord.com/api/v10";
const INTENTS = 1 | 512 | 4096 | 32768; // guilds, guild messages, DMs, message content
export async function runDiscordBridge(config, assistant, access) {
    const token = config.botToken;
    if (!token)
        throw new Error(`Discord token is missing. Set ${config.botTokenEnv}.`);
    if (typeof WebSocket !== "function")
        throw new Error("This Node runtime does not provide WebSocket.");
    const rateLimiter = new ConnectorRateLimiter(config.maxMessagesPerMinute);
    let stopped = false;
    process.once("SIGINT", () => {
        stopped = true;
    });
    process.once("SIGTERM", () => {
        stopped = true;
    });
    console.log("Discord bridge is running. Press Ctrl+C to stop.");
    while (!stopped) {
        try {
            await connectDiscordGateway(token, config, assistant, () => stopped, access, rateLimiter);
        }
        catch (error) {
            if (stopped)
                break;
            console.error(error instanceof Error ? error.message : error);
            await new Promise((resolve) => setTimeout(resolve, 5000));
        }
    }
}
async function connectDiscordGateway(token, config, assistant, shouldStop, access, rateLimiter) {
    await new Promise((resolve, reject) => {
        const socket = new WebSocket(DISCORD_GATEWAY_URL);
        let heartbeat;
        let sequence = null;
        let botUserId;
        const send = (payload) => socket.send(JSON.stringify(payload));
        socket.addEventListener("open", () => {
            // Discord sends HELLO first; identify happens after we know heartbeat interval.
        });
        socket.addEventListener("message", (event) => {
            void (async () => {
                const packet = JSON.parse(String(event.data));
                if (typeof packet.s === "number")
                    sequence = packet.s;
                if (packet.op === 10) {
                    const interval = Number(packet.d.heartbeat_interval);
                    heartbeat = setInterval(() => send({ op: 1, d: sequence }), interval);
                    heartbeat.unref?.();
                    send({
                        op: 2,
                        d: {
                            token,
                            intents: INTENTS,
                            properties: { os: process.platform, browser: "viser", device: "viser" }
                        }
                    });
                    return;
                }
                if (packet.op === 1) {
                    send({ op: 1, d: sequence });
                    return;
                }
                if (packet.t === "READY") {
                    botUserId = packet.d.user.id;
                    console.log(`Discord connected as ${packet.d.user.username}.`);
                    return;
                }
                if (packet.t === "MESSAGE_CREATE") {
                    await handleDiscordMessage(token, config, assistant, packet.d, botUserId, access, rateLimiter);
                }
            })().catch((error) => {
                if (heartbeat)
                    clearInterval(heartbeat);
                reject(error instanceof Error ? error : new Error(String(error)));
                try {
                    socket.close();
                }
                catch {
                    // The promise rejection above is enough; close failures are ignored.
                }
            });
        });
        socket.addEventListener("error", () => reject(new Error("Discord gateway socket error.")));
        socket.addEventListener("close", () => {
            if (heartbeat)
                clearInterval(heartbeat);
            if (shouldStop())
                resolve();
            else
                reject(new Error("Discord gateway closed; reconnecting."));
        });
    });
}
export async function handleDiscordMessage(token, config, assistant, message, botUserId, access, rateLimiter) {
    if (!message.content || message.author.bot || message.author.id === botUserId)
        return;
    const staticAllowlist = [...config.allowedChannelIds, ...config.defaultChannelIds];
    if (config.allowedChannelIds.length > 0 && !staticAllowlist.includes(message.channel_id))
        return;
    const normalized = normalizeDiscordInput(message.content, config.prefix, botUserId, Boolean(message.guild_id));
    if (!normalized)
        return;
    if (access && !(await access.isAllowed("discord", message.channel_id, staticAllowlist))) {
        const label = message.author.username ? `@${message.author.username}` : `discord:${message.channel_id}`;
        const paired = await access.tryPairCommand(normalized, "discord", message.channel_id, label);
        await sendDiscordMessage(token, message.channel_id, paired ? pairedMessage("discord") : pairingRequiredMessage("discord"));
        return;
    }
    if (connectorInputTooLong(normalized, config.maxInputChars)) {
        await sendDiscordMessage(token, message.channel_id, connectorInputLimitMessage(config.maxInputChars));
        return;
    }
    const rate = rateLimiter?.check(`discord:${message.channel_id}`);
    if (rate && !rate.allowed) {
        await sendDiscordMessage(token, message.channel_id, connectorRateLimitMessage(rate.retryAfterMs));
        return;
    }
    try {
        const answer = await assistant.handle(normalized, `discord:${message.channel_id}`, { source: "discord" });
        await sendDiscordMessage(token, message.channel_id, answer);
    }
    catch (error) {
        const detail = error instanceof Error ? error.message : String(error);
        await sendDiscordMessage(token, message.channel_id, `Viser error:\n${detail}`);
    }
}
export function normalizeDiscordInput(content, prefix, botUserId, isGuild) {
    const trimmed = content.trim();
    const mention = botUserId ? `<@${botUserId}>` : undefined;
    const nicknameMention = botUserId ? `<@!${botUserId}>` : undefined;
    if (!isGuild)
        return trimmed;
    if (trimmed.startsWith(prefix))
        return trimmed.slice(prefix.length).trim() || "/help";
    if (mention && trimmed.startsWith(mention))
        return trimmed.slice(mention.length).trim() || "/help";
    if (nicknameMention && trimmed.startsWith(nicknameMention))
        return trimmed.slice(nicknameMention.length).trim() || "/help";
    return undefined;
}
export async function sendDiscordMessage(token, channelId, text, options = {}) {
    for (const chunk of chunkText(text, 1900)) {
        try {
            const response = await fetchWithTimeout(options.fetchImpl ?? fetch, `${DISCORD_API_BASE}/channels/${channelId}/messages`, {
                method: "POST",
                headers: {
                    authorization: `Bot ${token}`,
                    "content-type": "application/json"
                },
                body: JSON.stringify({ content: chunk })
            }, options.timeoutMs ?? DEFAULT_FETCH_TIMEOUT_MS);
            if (!response.ok) {
                const body = await response.text();
                throw new Error(`Discord send failed: ${response.status} ${body}`);
            }
        }
        catch (error) {
            const message = error instanceof Error ? error.message : String(error);
            throw new Error(redactToken(message, token));
        }
    }
}
function redactToken(detail, token) {
    return detail.split(token).join("[REDACTED]");
}
